import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

function makeHeaders(entries: Record<string, string>): Headers {
  return new Headers(entries)
}

// --- geo() with Vercel headers ---

{
  const headers = makeHeaders({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })

  console.assert(result.city === 'San Francisco', 'city should be San Francisco')
  console.assert(result.countryCode === 'US', 'countryCode should be US')
  console.assert(result.country === 'United States', 'country should be United States')
  console.assert(result.region === 'CA', 'region should be CA')
  console.assert(result.latitude === '37.7749', 'latitude should be 37.7749')
  console.assert(result.longitude === '-122.4194', 'longitude should be -122.4194')
  console.assert(
    result.timezone === 'America/Los_Angeles',
    'timezone should be America/Los_Angeles'
  )
  console.log('PASS: geo() with Vercel headers')
}

// --- geoFromHeaders() with Cloudflare fallback ---

{
  const headers = makeHeaders({
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  console.assert(
    result.countryCode === 'GB',
    'countryCode should fall back to cf-ipcountry'
  )
  console.assert(
    result.country === 'United Kingdom',
    'country should be United Kingdom from Cloudflare header'
  )
  console.assert(result.city === undefined, 'city should be undefined')
  console.assert(result.region === undefined, 'region should be undefined')
  console.assert(result.latitude === undefined, 'latitude should be undefined')
  console.assert(result.longitude === undefined, 'longitude should be undefined')
  console.assert(result.timezone === undefined, 'timezone should be undefined')
  console.log('PASS: geoFromHeaders() with Cloudflare fallback')
}

// --- Vercel header takes precedence over Cloudflare ---

{
  const headers = makeHeaders({
    'x-vercel-ip-country': 'DE',
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  console.assert(
    result.countryCode === 'DE',
    'Vercel header should take precedence over Cloudflare'
  )
  console.assert(result.country === 'Germany', 'country should be Germany')
  console.log('PASS: Vercel header takes precedence over Cloudflare')
}

// --- Missing headers return undefined fields ---

{
  const headers = makeHeaders({})
  const result = geo({ headers })

  console.assert(result.city === undefined, 'city should be undefined')
  console.assert(result.country === undefined, 'country should be undefined')
  console.assert(result.countryCode === undefined, 'countryCode should be undefined')
  console.assert(result.region === undefined, 'region should be undefined')
  console.assert(result.latitude === undefined, 'latitude should be undefined')
  console.assert(result.longitude === undefined, 'longitude should be undefined')
  console.assert(result.timezone === undefined, 'timezone should be undefined')
  console.log('PASS: missing headers return undefined fields')
}

// --- Country name lookup from countryCode ---

{
  const testCases: Array<[string, string]> = [
    ['US', 'United States'],
    ['GB', 'United Kingdom'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['JP', 'Japan'],
    ['CN', 'China'],
    ['IN', 'India'],
    ['BR', 'Brazil'],
    ['AU', 'Australia'],
    ['CA', 'Canada'],
  ]

  for (const [code, expectedName] of testCases) {
    const headers = makeHeaders({ 'x-vercel-ip-country': code })
    const result = geo({ headers })
    console.assert(
      result.country === expectedName,
      `country for ${code} should be ${expectedName}, got ${result.country}`
    )
  }
  console.log('PASS: country name lookup from countryCode')
}

// --- Unknown country code returns undefined for country name ---

{
  const headers = makeHeaders({ 'x-vercel-ip-country': 'ZZ' })
  const result = geo({ headers })

  console.assert(result.countryCode === 'ZZ', 'countryCode should be ZZ')
  console.assert(
    result.country === undefined,
    'country should be undefined for unknown code'
  )
  console.log('PASS: unknown country code returns undefined for country name')
}

// --- isInRegion() with matching regions ---

{
  const geoData = { countryCode: 'US', country: 'United States' }
  console.assert(
    isInRegion(geoData, ['US', 'CA', 'GB']) === true,
    'US should be in [US, CA, GB]'
  )
  console.log('PASS: isInRegion() with matching region')
}

// --- isInRegion() with non-matching regions ---

{
  const geoData = { countryCode: 'DE', country: 'Germany' }
  console.assert(
    isInRegion(geoData, ['US', 'CA', 'GB']) === false,
    'DE should not be in [US, CA, GB]'
  )
  console.log('PASS: isInRegion() with non-matching region')
}

// --- isInRegion() is case-insensitive ---

{
  const geoData = { countryCode: 'us' }
  console.assert(
    isInRegion(geoData, ['US']) === true,
    'case-insensitive: us should match US'
  )

  const geoData2 = { countryCode: 'US' }
  console.assert(
    isInRegion(geoData2, ['us']) === true,
    'case-insensitive: US should match us'
  )
  console.log('PASS: isInRegion() is case-insensitive')
}

// --- isInRegion() with missing countryCode ---

{
  const geoData = {}
  console.assert(
    isInRegion(geoData, ['US']) === false,
    'missing countryCode should return false'
  )
  console.log('PASS: isInRegion() with missing countryCode')
}

// --- geoDistance() New York to London ~5570 km ---

{
  // New York: 40.7128° N, 74.0060° W
  // London: 51.5074° N, 0.1278° W
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  const diff = Math.abs(distance - 5570)
  console.assert(
    diff < 50,
    `NY to London should be ~5570 km (got ${distance}, diff ${diff})`
  )
  console.log(`PASS: geoDistance() NY to London = ${distance.toFixed(1)} km`)
}

// --- geoDistance() same point should be 0 ---

{
  const distance = geoDistance('0', '0', '0', '0')
  console.assert(distance === 0, `same point distance should be 0, got ${distance}`)
  console.log('PASS: geoDistance() same point = 0')
}

// --- geoDistance() antipodal points ~20015 km ---

{
  // North pole to south pole
  const distance = geoDistance('90', '0', '-90', '0')
  const diff = Math.abs(distance - 20015)
  console.assert(
    diff < 100,
    `pole to pole should be ~20015 km (got ${distance}, diff ${diff})`
  )
  console.log(`PASS: geoDistance() pole to pole = ${distance.toFixed(1)} km`)
}

console.log('\nAll geo tests passed!')

